WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/49.0/connection.js")} 

//Obtenemos el id de la organizacion
var idOrganizacion = '{!$Organization.Id}';

//Objeto url
var parametros = {};

var url = '';

if(checkCanAddItem()){

console.log(1);

if(idOrganizacion == '00DJ0000003K208'){

//Cargamos parámetro y valor

parametros['CF00NJ0000001Fncr'] = '{!Transaccion__c.Name}';
parametros['CF00NJ0000001Fncr_lkid'] = '{!Item_de_DUP__c.TransaccionId__c}';
parametros['CF00NJ0000001GHrh'] = '{!Transaccion__c.Obtentor__c}';
parametros['CF00NJ0000001GHrh_lkid'] = '{!Item_de_DUP__c.Obtentor__c}';
parametros['CF00NJ0000001Gkln'] = '{!Transaccion__c.Campana__c}';
parametros['CF00NJ0000001Gkln_lkid'] = '{!Item_de_DUP__c.Campana_Agricola__c}';

url = '/a0P/e?';


}else if(idOrganizacion == '00DJ0000003KAs8'){

//Cargamos parámetro y valor

parametros['CF00NG000000DvZj3'] = '{!Transaccion__c.Name}';
parametros['CF00NG000000DvZj3_lkid'] = '{!Item_de_DUP__c.TransaccionId__c}';
parametros['CF00NG000000DvZjx'] = '{!Transaccion__c.Obtentor__c}';
parametros['CF00NG000000DvZjx_lkid'] =  '{!Item_de_DUP__c.Obtentor__c}';
parametros['CF00NJ0000001A7Ke'] = '{!Transaccion__c.Campana__c}';
parametros['CF00NJ0000001A7Ke_lkid'] = '{!Item_de_DUP__c.Campana_Agricola__c}';

url = '/a0L/e?';

}else if(idOrganizacion == '00DG0000000ii42'){

//Cargamos parámetro y valor

parametros['CF00NG000000DvZj3'] = '{!Transaccion__c.Name}';
parametros['CF00NG000000DvZj3_lkid'] = '{!Transaccion__c.Id}';
parametros['CF00NG000000DvZjx'] = '{!Transaccion__c.Obtentor__c}';
parametros['CF00NG000000DvZjx_lkid'] =  '{!Item_de_DUP__c.Obtentor__c}';
parametros['CF00NG000000Dww8P'] = '{!Transaccion__c.Campana__c}';
parametros['CF00NG000000Dww8P_lkid'] = '{!Transaccion__c.CampanaId__c}';

url = '/a0L/e?';
}

//Si se introdujeron parametros
if(!isEmpty(parametros)){

var p = '';        

//Obtenemos la parametros
for(var prop in parametros) {
if(parametros.hasOwnProperty(prop)){
p += (p.length == 0)?prop+'='+parametros[prop]:'&'+prop+'='+parametros[prop];
}
}

//Completamos la URL
url += p+'&retURL='+'{!Transaccion__c.Id}';

//Redirigimos
redirect(url);

}

}

function redirect(url){

if(inIframe()){

window.top.location.href = url;

}else{


window.location.href = url;


}

}

function isEmpty(obj) {
    for(var prop in obj) {
        if(obj.hasOwnProperty(prop))
            return false;
    }

    return true;
}

function inIframe() {
    try {
        return window.self !== window.top;
    } catch (e) {
        return true;
    }
}

function checkCanAddItem(){

// Obtenemos el Nombre del obtentor
var query = "SELECT Id, Name, Z9_Lineas_Totales_DUP__c, Obtentor__r.Name FROM Transaccion__c WHERE Id = '{!Transaccion__c.Id}' limit 1";

var result = sforce.connection.query(query); 
var records = result.getArray("records"); 

console.log(records);

if(records[0]){

var transaccion = records[0];

if(parseInt(transaccion.Z9_Lineas_Totales_DUP__c)>0){

if(transaccion.Obtentor__r.Name.toLowerCase().indexOf('XX')!=-1){

alert('{!$Label.Error_Nuevo_Item_BUCK}');
return false;

}

}

}


return true;

}
